#!/usr/bin/env python3
"""
Smooth Fence USA — Watermark Script
------------------------------------
Adds watermark to all photos in a folder:
  • Bottom-left:  smoothfenceusa.com  (white text, subtle shadow)
  • Bottom-right: logo (semi-transparent)

Usage:
    python3 agregar_marca_de_agua.py

Edit FOTO_FOLDER below to point to your photos folder.
"""

import os
import sys
import subprocess
import shutil
from pathlib import Path
from PIL import Image, ImageDraw, ImageFont, ImageFilter

# ─── CONFIG ──────────────────────────────────────────────────────────────────

FOTO_FOLDER   = os.path.expanduser(
    "~/Library/Mobile Documents/com~apple~CloudDocs/2026/Smooth Fence /Fotos"
)
OUTPUT_FOLDER = os.path.expanduser(
    "~/Library/Mobile Documents/com~apple~CloudDocs/2026/Smooth Fence /Fotos_con_marca"
)

WEBSITE_TEXT  = "smoothfenceusa.com"
LOGO_OPACITY  = 55          # % transparency of logo (0=invisible, 100=solid)
TEXT_OPACITY  = 75          # % opacity of website text
LOGO_WIDTH_PCT = 0.18       # logo width = 18% of photo width
PADDING       = 0.025       # padding from edges = 2.5% of photo width
TEXT_SIZE_PCT  = 0.030      # font size = 3% of photo width

# ─── PATHS ───────────────────────────────────────────────────────────────────

SCRIPT_DIR  = Path(__file__).parent
LOGO_SVG    = SCRIPT_DIR / "public" / "logo.svg"   # adjust if needed
LOGO_PNG_TMP = Path("/tmp/sfusa_logo_wm.png")

SUPPORTED = {".jpg", ".jpeg", ".png", ".heic", ".webp"}

# Logo embedded as base64 (no ImageMagick needed)
LOGO_B64 = ""


# ─── HELPERS ─────────────────────────────────────────────────────────────────

# SVG conversion not needed — logo is embedded as base64


def prepare_logo(logo_src, target_width: int, opacity_pct: int) -> Image.Image:
    """Load logo, remove white background, resize, set opacity."""
    logo = Image.open(logo_src).convert("RGBA")

    # Remove near-white background pixels
    data = logo.getdata()
    new_data = []
    for r, g, b, a in data:
        if r > 230 and g > 230 and b > 230:
            new_data.append((r, g, b, 0))   # transparent
        else:
            new_data.append((r, g, b, a))
    logo.putdata(new_data)

    # Resize keeping aspect ratio
    ratio = target_width / logo.width
    new_h = int(logo.height * ratio)
    logo = logo.resize((target_width, new_h), Image.LANCZOS)

    # Apply opacity
    r, g, b, a = logo.split()
    a = a.point(lambda x: int(x * opacity_pct / 100))
    logo = Image.merge("RGBA", (r, g, b, a))

    return logo


def get_font(size: int):
    """Try to load a clean system font, fall back to default."""
    candidates = [
        "/System/Library/Fonts/Helvetica.ttc",
        "/System/Library/Fonts/SFNSText.ttf",
        "/System/Library/Fonts/Arial.ttf",
        "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf",
    ]
    for path in candidates:
        if os.path.exists(path):
            try:
                from PIL import ImageFont
                return ImageFont.truetype(path, size)
            except Exception:
                continue
    from PIL import ImageFont
    return ImageFont.load_default()


def draw_text_with_shadow(draw, x, y, text, font, text_color, shadow_color, offset=2):
    """Draw text with a subtle drop shadow."""
    draw.text((x + offset, y + offset), text, font=font, fill=shadow_color)
    draw.text((x, y), text, font=font, fill=text_color)


def watermark_image(photo_path: Path, output_path: Path, logo: Image.Image, font_size: int):
    """Apply watermarks to a single photo."""
    img = Image.open(photo_path)

    # Handle HEIC / other formats — convert to RGB
    if img.mode in ("P", "CMYK"):
        img = img.convert("RGB")
    elif img.mode == "RGBA":
        pass  # keep
    else:
        img = img.convert("RGB")

    w, h = img.size
    padding = int(w * PADDING)

    # ── Composite logo (bottom-right) ────────────────────────────────────────
    logo_w = int(w * LOGO_WIDTH_PCT)
    logo_ratio = logo_w / logo.width
    logo_h = int(logo.height * logo_ratio)
    logo_resized = logo.resize((logo_w, logo_h), Image.LANCZOS)

    # Work on RGBA copy
    base = img.convert("RGBA")
    lx = w - logo_w - padding
    ly = h - logo_h - padding
    base.paste(logo_resized, (lx, ly), logo_resized)

    # ── Website text (bottom-left) ────────────────────────────────────────────
    font = get_font(font_size)
    draw = ImageDraw.Draw(base)

    text_alpha = int(255 * TEXT_OPACITY / 100)
    text_color   = (255, 255, 255, text_alpha)
    shadow_color = (0, 0, 0, int(text_alpha * 0.6))

    # Measure text
    bbox = draw.textbbox((0, 0), WEBSITE_TEXT, font=font)
    tw, th = bbox[2] - bbox[0], bbox[3] - bbox[1]

    tx = padding
    ty = h - th - padding

    draw_text_with_shadow(draw, tx, ty, WEBSITE_TEXT, font, text_color, shadow_color)

    # ── Save ──────────────────────────────────────────────────────────────────
    output_path.parent.mkdir(parents=True, exist_ok=True)
    ext = output_path.suffix.lower()
    final = base.convert("RGB") if ext in (".jpg", ".jpeg") else base
    final.save(str(output_path), quality=92)


# ─── MAIN ────────────────────────────────────────────────────────────────────

def main():
    foto_dir   = Path(FOTO_FOLDER)
    output_dir = Path(OUTPUT_FOLDER)

    if not foto_dir.exists():
        print(f"\n❌  Carpeta no encontrada:\n   {foto_dir}\n")
        print("   Edita la variable FOTO_FOLDER en el script y vuelve a correrlo.")
        sys.exit(1)

    photos = [p for p in foto_dir.iterdir()
              if p.suffix.lower() in SUPPORTED and not p.name.startswith(".")]

    if not photos:
        print(f"\n⚠️  No se encontraron fotos en:\n   {foto_dir}\n")
        sys.exit(0)

    print(f"\n📸  {len(photos)} foto(s) encontrada(s) en:\n   {foto_dir}")
    print(f"💾  Guardando en:\n   {output_dir}\n")

    # Load logo from embedded base64
    import base64, io
    logo_bytes = base64.b64decode(LOGO_B64)
    logo = prepare_logo(io.BytesIO(logo_bytes), 999, LOGO_OPACITY)  # 999 = full res, resized per photo

    # Font size: ~3% of average photo width
    sample = Image.open(photos[0])
    font_size = max(22, int(sample.width * TEXT_SIZE_PCT))

    ok = 0
    for i, photo in enumerate(sorted(photos), 1):
        out = output_dir / photo.name
        try:
            watermark_image(photo, out, logo, font_size)
            print(f"  ✅  [{i}/{len(photos)}] {photo.name}")
            ok += 1
        except Exception as e:
            print(f"  ❌  [{i}/{len(photos)}] {photo.name} — {e}")

    print(f"\n🎉  Listo! {ok}/{len(photos)} fotos procesadas.")
    print(f"📂  Abre la carpeta:\n   {output_dir}\n")

    # Open output folder in Finder
    try:
        subprocess.run(["open", str(output_dir)])
    except Exception:
        pass


if __name__ == "__main__":
    main()
